import Image from "next/image";

export default function SkillItemFilter() {

  return (
    <svg className="hidden">
      <filter id="liquidGlass" primitiveUnits="objectBoundingBox">
        <feImage x="0" y="0" width="100%" height="100%" result="map" href="data:image/webp;base64,"/>
        <feGaussianBlur in="SourceGraphic" stdDeviation="0.1" result="blur"/>
        <feDisplacementMap 
          id="disp" 
          in="blur" 
          in2="map" 
          scale="0.2" 
          xChannelSelector="R" 
          yChannelSelector="G">
        </feDisplacementMap>
      </filter>
    </svg>
  );
}
